7	#include <filesystem>
8	#include <cfloat>
9	#include <cmath>
10	#include <fstream>
11	#include <rime/algo/algebra.h>
12	#include <rime/algo/utilities.h>
13	#include <rime/dict/corrector.h>
14	#include <rime/dict/dict_compiler.h>
15	#include <rime/dict/dict_settings.h>
16	#include <rime/dict/dictionary.h>
17	#include <rime/dict/entry_collector.h>
18	#include <rime/dict/preset_vocabulary.h>
19	#include <rime/dict/prism.h>
20	#include <rime/dict/reverse_lookup_dictionary.h>
21	#include <rime/dict/table.h>
22	#include <rime/resource.h>
23	#include <rime/service.h>
24	
25	namespace rime {
26	
27	DictCompiler::DictCompiler(Dictionary* dictionary)
28	    : dict_name_(dictionary->name()),
29	      packs_(dictionary->packs()),
30	      prism_(dictionary->prism()),
31	      tables_(dictionary->tables()),
32	      source_resolver_(
33	          Service::instance().CreateResourceResolver({"source_file", "", ""})),
34	      target_resolver_(Service::instance().CreateStagingResourceResolver(
35	          {"target_file", "", ""})) {}
36	
37	DictCompiler::~DictCompiler() {}
38	
39	static bool load_dict_settings_from_file(DictSettings* settings,
40	                                         const path& dict_file) {
41	  std::ifstream fin(dict_file.c_str());
42	  bool success = settings->LoadDictHeader(fin);
43	  fin.close();
44	  return success;
45	}
46	
47	static bool get_dict_files_from_settings(vector<path>* dict_files,
48	                                         DictSettings& settings,
49	                                         ResourceResolver* source_resolver) {
50	  if (auto tables = settings.GetTables()) {
51	    for (auto it = tables->begin(); it != tables->end(); ++it) {
52	      string dict_name = As<ConfigValue>(*it)->str();
53	      auto dict_file = source_resolver->ResolvePath(dict_name + ".dict.yaml");
54	      if (!std::filesystem::exists(dict_file)) {
55	        LOG(ERROR) << "source file '" << dict_file << "' does not exist.";
56	        return false;
57	      }
58	      dict_files->push_back(dict_file);
59	    }
60	  }
61	  return true;
62	}
63	
64	static uint32_t compute_dict_file_checksum(uint32_t initial_checksum,
65	                                           const vector<path>& dict_files,
66	                                           DictSettings& settings) {
67	  if (dict_files.empty()) {
68	    return initial_checksum;
69	  }
70	  ChecksumComputer cc(initial_checksum);
71	  for (const auto& file_path : dict_files) {
72	    cc.ProcessFile(file_path);
73	  }
74	  if (settings.use_preset_vocabulary()) {
75	    cc.ProcessFile(PresetVocabulary::DictFilePath(settings.vocabulary()));
76	  }
77	  return cc.Checksum();
78	}
79	
80	bool DictCompiler::Compile(const path& schema_file) {
81	  LOG(INFO) << "compiling dictionary for " << schema_file;
82	  bool build_table_from_source = true;
83	  DictSettings settings;
84	  auto dict_file = source_resolver_->ResolvePath(dict_name_ + ".dict.yaml");
85	  if (!std::filesystem::exists(dict_file)) {
86	    LOG(ERROR) << "source file '" << dict_file << "' does not exist.";
87	    build_table_from_source = false;
88	  } else if (!load_dict_settings_from_file(&settings, dict_file)) {
89	    LOG(ERROR) << "failed to load settings from '" << dict_file << "'.";
90	    return false;
91	  }
92	  vector<path> dict_files;
93	  if (!get_dict_files_from_settings(&dict_files, settings,
94	                                    source_resolver_.get())) {
95	    return false;
96	  }
97	  uint32_t dict_file_checksum =
98	      compute_dict_file_checksum(0, dict_files, settings);
99	  uint32_t schema_file_checksum =
100	      schema_file.empty() ? 0 : Checksum(schema_file);
101	  bool rebuild_table = false;
102	  bool rebuild_prism = false;
103	  const auto& primary_table = tables_[0];
104	  if (primary_table->Exists() && primary_table->Load()) {
105	    if (build_table_from_source) {
106	      rebuild_table = primary_table->dict_file_checksum() != dict_file_checksum;
107	    } else {
108	      dict_file_checksum = primary_table->dict_file_checksum();
109	      LOG(INFO) << "reuse existing table: " << primary_table->file_path();
110	    }
111	    primary_table->Close();
112	  } else if (build_table_from_source) {
113	    rebuild_table = true;
114	  } else {
115	    LOG(ERROR) << "neither " << dict_name_ << ".dict.yaml nor " << dict_name_
116	               << ".table.bin exists.";
117	    return false;
118	  }
119	  if (prism_->Exists() && prism_->Load()) {
120	    rebuild_prism = prism_->dict_file_checksum() != dict_file_checksum ||
121	                    prism_->schema_file_checksum() != schema_file_checksum;
122	    prism_->Close();
123	  } else {
124	    rebuild_prism = true;
125	  }
126	  LOG(INFO) << dict_file << "[" << dict_files.size() << " file(s)]"
127	            << " (" << dict_file_checksum << ")";
128	  LOG(INFO) << schema_file << " (" << schema_file_checksum << ")";
129	  {
130	    the<ResourceResolver> resolver(
131	        Service::instance().CreateDeployedResourceResolver(
132	            {"find_reverse_db", "", ".reverse.bin"}));
133	    ReverseDb reverse_db(resolver->ResolvePath(dict_name_));
134	    if (!reverse_db.Exists() || !reverse_db.Load() ||
135	        reverse_db.dict_file_checksum() != dict_file_checksum) {
136	      rebuild_table = true;
137	    }
138	  }
139	  if (build_table_from_source && (options_ & kRebuildTable)) {
140	    rebuild_table = true;
141	  }
142	  if (options_ & kRebuildPrism) {
143	    rebuild_prism = true;
144	  }
145	  Syllabary syllabary;
146	  if (rebuild_table) {
147	    EntryCollector collector;
148	    if (!BuildTable(0, collector, &settings, dict_files, dict_file_checksum)) {
149	      return false;
150	    }
151	    syllabary = std::move(collector.syllabary);
152	  } else if (packs_.size() > 0) {
153	    if (primary_table->Load() && primary_table->GetSyllabary(&syllabary))
154	      primary_table->Close();
155	    else
156	      LOG(WARNING) << "couldn't load syllabary from '" << schema_file << "'";
157	  }
158	  if (rebuild_prism &&
159	      !BuildPrism(schema_file, dict_file_checksum, schema_file_checksum)) {
160	    return false;
161	  }
162	  for (int table_index = 1; table_index < tables_.size(); ++table_index) {
163	    const auto& pack_name = packs_[table_index - 1];
164	    auto pack_table = tables_[table_index];
165	    EntryCollector collector(std::move(syllabary));
166	    DictSettings settings;
167	    auto dict_file = source_resolver_->ResolvePath(pack_name + ".dict.yaml");
168	    if (!std::filesystem::exists(dict_file)) {
169	      if (pack_table->Exists())
170	        LOG(INFO) << "pack source file '" << dict_file
171	                  << "' does not exist, using prebuilt table '"
172	                  << pack_table->file_path() << "'";
173	      else
174	        LOG(ERROR) << "neither pack source file '" << dict_file
175	                   << "' nor a prebuilt table exists";
176	      continue;
177	    }
178	    if (!load_dict_settings_from_file(&settings, dict_file)) {
179	      LOG(ERROR) << "failed to load settings from '" << dict_file << "'.";
180	      continue;
181	    }
182	    vector<path> dict_files;
183	    if (!get_dict_files_from_settings(&dict_files, settings,
184	                                      source_resolver_.get())) {
185	      continue;
186	    }
187	    uint32_t pack_file_checksum =
188	        compute_dict_file_checksum(dict_file_checksum, dict_files, settings);
189	    bool rebuild_pack = true;
190	    if (pack_table->Exists() && pack_table->Load()) {
191	      rebuild_pack = pack_table->dict_file_checksum() != pack_file_checksum;
192	    }
193	    if (rebuild_pack) {
194	      LOG(INFO) << "rebuilding pack '" << pack_name << "'";
195	      if (!BuildTable(table_index, collector, &settings, dict_files,
196	                      pack_file_checksum)) {
197	        LOG(ERROR) << "failed to build pack: " << pack_name;
198	      }
199	    } else {
200	      LOG(INFO) << "pack '" << pack_name << "' reuses up-to-date table '"
201	                << pack_table->file_path() << "'";
202	    }
203	    syllabary = std::move(collector.syllabary);
204	    pack_table->Close();
205	  }
206	  // done!
207	  return true;
208	}
209	
210	static path relocate_target(const path& source_path,
211	                            ResourceResolver* target_resolver) {
212	  auto resource_id = source_path.filename().u8string();
213	  return target_resolver->ResolvePath(resource_id);
214	}
215	
216	bool DictCompiler::BuildTable(int table_index,
217	                              EntryCollector& collector,
218	                              DictSettings* settings,
219	                              const vector<path>& dict_files,
220	                              uint32_t dict_file_checksum) {
221	  auto& table = tables_[table_index];
222	  auto target_path =
223	      relocate_target(table->file_path(), target_resolver_.get());
224	  LOG(INFO) << "building table: " << target_path;
225	  table = New<Table>(target_path);
226	
227	  collector.Configure(settings);
228	  collector.Collect(dict_files);
229	  if (options_ & kDump) {
230	    path dump_path(table->file_path());
231	    dump_path.replace_extension(".txt");
232	    collector.Dump(dump_path);
233	  }
234	  Vocabulary vocabulary;
235	  // build .table.bin
236	  {
237	    map<string, SyllableId> syllable_to_id;
238	    SyllableId syllable_id = 0;
239	    for (const auto& s : collector.syllabary) {
240	      syllable_to_id[s] = syllable_id++;
241	    }
242	    for (const auto& r : collector.entries) {
243	      Code code;
244	      for (const auto& s : r->raw_code) {
245	        code.push_back(syllable_to_id[s]);
246	      }
247	      // release memory in time to reduce memory usage
248	      RawCode().swap(r->raw_code);
249	      auto ls = vocabulary.LocateEntries(code);
250	      if (!ls) {
251	        LOG(ERROR) << "Error locating entries in vocabulary.";
252	        continue;
253	      }
254	      auto e = New<ShortDictEntry>();
255	      e->code.swap(code);
256	      e->text.swap(r->text);
257	      e->weight = log(r->weight > 0 ? r->weight : DBL_EPSILON);
258	      ls->push_back(e);
259	    }
260	    // release memory in time to reduce memory usage
261	    vector<of<RawDictEntry>>().swap(collector.entries);
262	    if (settings->sort_order() != "original") {
263	      vocabulary.SortHomophones();
264	    }
265	    table->Remove();
266	    if (!table->Build(collector.syllabary, vocabulary, collector.num_entries,
267	                      dict_file_checksum) ||
268	        !table->Save()) {
269	      return false;
270	    }
271	  }
272	  // build reverse db for the primary table
273	  if (table_index == 0 &&
274	      !BuildReverseDb(settings, collector, vocabulary, dict_file_checksum)) {
275	    return false;
276	  }
277	  return true;
278	}
279	
280	bool DictCompiler::BuildReverseDb(DictSettings* settings,
281	                                  const EntryCollector& collector,
282	                                  const Vocabulary& vocabulary,
283	                                  uint32_t dict_file_checksum) {
284	  // build .reverse.bin
285	  auto target_path = target_resolver_->ResolvePath(dict_name_ + ".reverse.bin");
286	  ReverseDb reverse_db(target_path);
287	  if (!reverse_db.Build(settings, collector.syllabary, vocabulary,
288	                        collector.stems, dict_file_checksum) ||
289	      !reverse_db.Save()) {
290	    LOG(ERROR) << "error building reversedb.";
291	    return false;
292	  }
293	  return true;
294	}
295	
296	bool DictCompiler::BuildPrism(const path& schema_file,
297	                              uint32_t dict_file_checksum,
298	                              uint32_t schema_file_checksum) {
299	  LOG(INFO) << "building prism...";
300	  auto target_path =
301	      relocate_target(prism_->file_path(), target_resolver_.get());
302	  prism_ = New<Prism>(target_path);
303	
304	  // get syllabary from primary table, which may not be rebuilt
305	  Syllabary syllabary;
306	  const auto& primary_table = tables_[0];
307	  if (!primary_table->Load() || !primary_table->GetSyllabary(&syllabary) ||
308	      syllabary.empty())
309	    return false;
310	  // apply spelling algebra and prepare corrections (if enabled)
311	  Script script;
312	  if (!schema_file.empty()) {
313	    Config config;
314	    if (!config.LoadFromFile(schema_file)) {
315	      LOG(ERROR) << "error loading prism definition from " << schema_file;
316	      return false;
317	    }
318	    Projection p;
319	    auto algebra = config.GetList("speller/algebra");
320	    if (algebra && p.Load(algebra)) {
321	      for (const auto& x : syllabary) {
322	        script.AddSyllable(x);
323	      }
324	      if (!p.Apply(&script)) {
325	        script.clear();
326	      }
327	    }
328	
329	#if 0
330	    // build corrector
331	    bool enable_correction = false; // Avoid if initializer to comfort compilers
332	    if (config.GetBool("translator/enable_correction", &enable_correction) &&
333	        enable_correction) {
334	      path corrector_path(prism_->file_path());
335	      corrector_path.replace_extension("");
336	      corrector_path.replace_extension(".correction.bin");
337	      auto target_path = relocate_target(corrector_path,
338	                                         target_resolver_.get());
339	      correction_ = New<EditDistanceCorrector>(target_path);
340	      if (correction_->Exists()) {
341	        correction_->Remove();
342	      }
343	      if (!correction_->Build(syllabary, &script,
344	                         dict_file_checksum, schema_file_checksum) ||
345	          !correction_->Save()) {
346	        return false;
347	      }
348	    }
349	#endif
350	  }
351	  if ((options_ & kDump) && !script.empty()) {
352	    path dump_path(prism_->file_path());
353	    dump_path.replace_extension(".txt");
354	    script.Dump(dump_path);
355	  }
356	  // build .prism.bin
357	  {
358	    prism_->Remove();
359	    if (!prism_->Build(syllabary, script.empty() ? nullptr : &script,
360	                       dict_file_checksum, schema_file_checksum) ||
361	        !prism_->Save()) {
362	      return false;
363	    }
364	  }
365	
366	  return true;
367	}
368	
369	}  // namespace rime
