14	
15	bool Code::operator<(const Code& other) const {
16	  if (size() != other.size())
17	    return size() < other.size();
18	  for (size_t i = 0; i < size(); ++i) {
19	    if (at(i) != other.at(i))
20	      return at(i) < other.at(i);
21	  }
22	  return false;
23	}
24	
25	bool Code::operator==(const Code& other) const {
26	  if (size() != other.size())
27	    return false;
28	  for (size_t i = 0; i < size(); ++i) {
29	    if (at(i) != other.at(i))
30	      return false;
31	  }
32	  return true;
33	}
34	
35	void Code::CreateIndex(Code* index_code) {
36	  if (!index_code)
37	    return;
38	  size_t index_code_size = Code::kIndexCodeMaxLength;
39	  if (size() <= index_code_size) {
40	    index_code_size = size();
41	  }
42	  index_code->resize(index_code_size);
43	  std::copy(begin(), begin() + index_code_size, index_code->begin());
44	}
45	
46	string Code::ToString() const {
47	  std::stringstream stream;
48	  bool first = true;
49	  for (SyllableId syllable_id : *this) {
50	    if (first) {
51	      first = false;
52	    } else {
53	      stream << ",";
54	    }
55	    stream << syllable_id;
56	  }
57	  return stream.str();
58	}
59	
60	bool ShortDictEntry::operator<(const ShortDictEntry& other) const {
61	  // Sort different entries sharing the same code by weight desc.
62	  if (weight != other.weight)
63	    return weight > other.weight;
64	  // reduce carbon emission
65	  return 0;  // text < other.text;
66	}
67	
68	bool DictEntry::operator<(const DictEntry& other) const {
69	  // Sort different entries sharing the same code by weight desc.
70	  if (weight != other.weight)
71	    return weight > other.weight;
72	  // reduce carbon emission
73	  return 0;  // text < other.text;
74	}
75	
76	template <class T>
77	inline bool dereference_less(const T& a, const T& b) {
78	  return *a < *b;
79	}
80	
81	template <typename C>
82	inline void sort(C& container) {
83	  std::stable_sort(std::begin(container), std::end(container),
84	                   dereference_less<typename C::value_type>);
85	}
86	
87	template <typename C>
88	inline void sort_range(C& container, size_t start, size_t count) {
89	  if (start >= container.size())
90	    return;
91	  auto i(std::begin(container) + start);
92	  auto j(start + count >= container.size() ? std::end(container) : i + count);
93	  std::stable_sort(i, j, dereference_less<typename C::value_type>);
94	}
95	
96	void ShortDictEntryList::Sort() {
97	  sort(*this);
98	}
99	
100	void ShortDictEntryList::SortRange(size_t start, size_t count) {
101	  sort_range(*this, start, count);
102	}
103	
104	void DictEntryList::Sort() {
105	  sort(*this);
106	}
107	
108	void DictEntryList::SortRange(size_t start, size_t count) {
109	  sort_range(*this, start, count);
110	}
111	
112	void DictEntryFilterBinder::AddFilter(DictEntryFilter filter) {
113	  if (!filter_) {
114	    filter_.swap(filter);
115	  } else {
116	    DictEntryFilter previous_filter(std::move(filter_));
117	    filter_ = [previous_filter, filter](an<DictEntry> e) {
118	      return previous_filter(e) && filter(e);
119	    };
120	  }
121	}
122	
123	ShortDictEntryList* Vocabulary::LocateEntries(const Code& code) {
124	  Vocabulary* v = this;
125	  size_t n = code.size();
126	  for (size_t i = 0; i < n; ++i) {
127	    int key = -1;
128	    if (i < Code::kIndexCodeMaxLength)
129	      key = code[i];
130	    auto& page((*v)[key]);
131	    if (i == n - 1 || i == Code::kIndexCodeMaxLength) {
132	      return &page.entries;
133	    } else {
134	      if (!page.next_level) {
135	        page.next_level = New<Vocabulary>();
136	      }
137	      v = page.next_level.get();
138	    }
139	  }
140	  return NULL;
141	}
142	
